-- SQL: rows in a fixed table
CREATE TABLE users (
  id    INT PRIMARY KEY,
  name  TEXT NOT NULL,
  email TEXT UNIQUE
);
INSERT INTO users VALUES (1, 'Ava', 'ava@x.io');

// NoSQL (document): a flexible JSON object
db.users.insertOne({
  _id: 1,
  name: "Ava",
  email: "ava@x.io",
  tags: ["beta", "pro"]   // add fields freely
});

-- Money must never half-move. One transaction, all-or-nothing:
BEGIN;
  UPDATE accounts SET balance = balance - 100 WHERE id = 1;
  UPDATE accounts SET balance = balance + 100 WHERE id = 2;
COMMIT;   -- both succeed, or neither does

// The order is already inside the user doc
db.users.findOne(
  { _id: 1 },
  { name: 1, "orders.total": 1 }   // one read, no join
);

CREATE TABLE users (
  id   SERIAL PRIMARY KEY,
  name TEXT NOT NULL
);
CREATE TABLE posts (
  id      SERIAL PRIMARY KEY,
  user_id INT REFERENCES users(id),
  title   TEXT NOT NULL
);
INSERT INTO users (name) VALUES ('Ava');
INSERT INTO posts (user_id, title) VALUES (1, 'Hello');

// posts live inside the user document
db.users.insertOne({
  _id: 1,
  name: "Ava",
  posts: [
    { id: 1, title: "Hello" }
  ]
});

// Read everything in one lookup, no join:
db.users.findOne({ _id: 1 });

// Add a post by pushing into the array:
db.users.updateOne(
  { _id: 1 },
  { $push: { posts: { id: 2, title: "Part 2" } } }
);
